class Solution:
    def earliestTime(self, tasks):
        best = None
        for s, t in tasks:
            f = s + t
            if best is None or f < best:
                best = f
        return best

solutions.python:
class Solution:
    def earliestTime(self, tasks):
        return min(s + t for s, t in tasks)

solutions.javascript:
var earliestTime = function(tasks) {
    let best = Infinity;
    for (const [s, t] of tasks) best = Math.min(best, s + t);
    return best;
};
